SELECT COUNT(version_id)
FROM dashboard_versions
WHERE config_id = 'config_id';

SELECT DISTINCT u.user_id, u.user_name, u.email, u.role, u.job_title, u.department, u.business_unit_id
FROM users u
JOIN access_logs al ON u.user_id = al.user_id;

SELECT * 
FROM layout_specifications
LIMIT 5;

SELECT user_name, email
FROM users
WHERE user_id IN (
  SELECT created_by
  FROM tables
  WHERE created_by IN (
    SELECT created_by
    FROM link_sources
  )
);

SELECT *
FROM tables
ORDER BY table_name;

SELECT COUNT(*) 
FROM tables 
WHERE is_active = 1;
